#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int maxOnes(int* arr, int n, int k) {
    int maxOnes = 0;
    int windowOnes = 0;
    for (int i = 0; i < k; i++) {
        windowOnes += arr[i];
    }
    maxOnes = windowOnes;
    for (int i = k; i < n; i++) {
        windowOnes = windowOnes - arr[i - k] + arr[i];
        maxOnes = (maxOnes > windowOnes) ? maxOnes : windowOnes;
    }
    return maxOnes;
}

int main() {
    int t = 1;
    while (t--) {
        int n, k, p;
        scanf("%d %d %d", &n, &k, &p);
        int* arr = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        char* queries = (char*) malloc((p + 1) * sizeof(char));
        scanf("%s", queries);
        for (int i = 0; i < p; i++) {
            if (queries[i] == '!') {
                int temp = arr[n - 1];
                for (int j = n - 1; j > 0; j--) {
                    arr[j] = arr[j - 1];
                }
                arr[0] = temp;
            } else {
                printf("%d\n", maxOnes(arr, n, k));
            }
        }
        free(arr);
        free(queries);
    }
    return 0;
}

