import java.util.Scanner;
public class Main {
    public static int maxOnes(int[] arr, int k) {
        int maxOnes = 0;
        int windowOnes = 0;
        for (int i = 0; i < k; i++) {
            windowOnes += arr[i];
        }
        maxOnes = windowOnes;
        for (int i = k; i < arr.length; i++) {
            windowOnes = windowOnes - arr[i - k] + arr[i];
            maxOnes = (maxOnes > windowOnes) ? maxOnes : windowOnes;
        }
        return maxOnes;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = 1;
        while (t-- > 0) {
            int n = scanner.nextInt();
            int k = scanner.nextInt();
            int p = scanner.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt();
            }
            String queries = scanner.next();
            for (int i = 0; i < p; i++) {
                if (queries.charAt(i) == '!') {
                    int temp = arr[n - 1];
                    for (int j = n - 1; j > 0; j--) {
                        arr[j] = arr[j - 1];
                    }
                    arr[0] = temp;
                } else {
                    System.out.println(maxOnes(arr, k));
                }
            }
        }
    }
}

